#nullable enable // autogenerated

namespace MVZ2Logic.Options
{
    public abstract class OptionButtonDefinition : OptionWidgetDefinition
    {
        public OptionButtonDefinition(string nsp, string name) : base(nsp, name)
        {
        }
        public override OptionWidgetType GetItemType()
        {
            return OptionWidgetType.Button;
        }
        public virtual string GetLabelValue(IOptionContext context) => string.Empty;
        public abstract void OnClick();
    }
}
